import React, { useState } from 'react';
import { MapContainer, TileLayer, Marker, useMapEvents } from 'react-leaflet';
import { X, MapPin, Navigation, Store } from 'lucide-react';
import L from 'leaflet';

// 1. CREAMOS EL ICONO DE LOCAL (SVG)
// Este es un diseño de tienda con techo naranja
const iconoLocalPropio = L.divIcon({
  className: 'custom-icon',
  html: `
    <div style="
      background-color: #e67e22; 
      width: 40px; 
      height: 40px; 
      border-radius: 10px; 
      display: flex; 
      justify-content: center; 
      align-items: center; 
      border: 3px solid white;
      box-shadow: 0 2px 5px rgba(0,0,0,0.3);
    ">
      <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="white" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
        <path d="m2 7 4.41-4.41A2 2 0 0 1 7.83 2h8.34a2 2 0 0 1 1.42.59L22 7"></path>
        <path d="M4 12v8a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2v-8"></path>
        <path d="M15 22v-4a2 2 0 0 0-2-2h-2a2 2 0 0 0-2 2v4"></path>
        <path d="M2 7h20"></path>
        <path d="M22 7v3a2 2 0 0 1-2 2v0a2.7 2.7 0 0 1-1.59-.63.7.7 0 0 0-.82 0A2.7 2.7 0 0 1 16 12a2.7 2.7 0 0 1-1.59-.63.7.7 0 0 0-.82 0A2.7 2.7 0 0 1 12 12a2.7 2.7 0 0 1-1.59-.63.7.7 0 0 0-.82 0A2.7 2.7 0 0 1 8 12a2.7 2.7 0 0 1-1.59-.63.7.7 0 0 0-.82 0A2.7 2.7 0 0 1 4 12v0a2 2 0 0 1-2-2V7"></path>
      </svg>
    </div>`,
  iconSize: [40, 40],
  iconAnchor: [20, 40], // La punta del icono queda en la coordenada exacta
});

function LocationPicker({ position, setPosition, onAddressFound }) {
  useMapEvents({
    async click(e) {
      const { lat, lng } = e.latlng;
      setPosition([lat, lng]);
      
      try {
        const response = await fetch(
          `https://nominatim.openstreetmap.org/reverse?format=jsonv2&lat=${lat}&lon=${lng}`
        );
        const data = await response.json();
        if (data.address) {
          onAddressFound(data.address);
        }
      } catch (error) {
        console.error("Error buscando dirección", error);
      }
    }
  });

  // USAMOS EL ICONO ACÁ ABAJO
  return position ? <Marker position={position} icon={iconoLocalPropio} /> : null;
}

const ModalNuevaSucursal = ({ onClose, onSave }) => {
  const [nombre, setNombre] = useState('');
  const [direccion, setDireccion] = useState('');
  const [provincia, setProvincia] = useState('');
  const [ciudad, setCiudad] = useState('');
  const [coords, setCoords] = useState([-26.816, -65.216]);

  const handleAddressFound = (address) => {
    const calle = address.road || '';
    const numero = address.house_number || '';
    setDireccion(`${calle} ${numero}`.trim());
    setCiudad(address.city || address.town || address.village || '');
    setProvincia(address.state || '');
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!ciudad || !direccion) return alert("Hacé clic en el mapa para ubicar el local");
    onSave({ nombre, direccion, provincia, ciudad, lat: coords[0], lng: coords[1] });
  };

  return (
    <div style={modalOverlay}>
      <div style={modalContent}>
        <div style={headerStyle}>
          <div>
            <h3 style={{ margin: 0, color: '#1e293b' }}>Registrar Sucursal</h3>
            <p style={{ margin: 0, fontSize: '0.8rem', color: '#64748b' }}>Marcá el punto exacto en el mapa</p>
          </div>
          <button onClick={onClose} style={closeBtn}><X size={20} /></button>
        </div>

        <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
          <div style={inputGroup}>
            <label style={labelStyle}>Nombre del Local</label>
            <input required style={inputStyle} value={nombre} onChange={e => setNombre(e.target.value)} placeholder="Ej: Mi Almacén" />
          </div>

          <div style={mapContainerStyle}>
            <MapContainer center={coords} zoom={15} style={{ height: '100%' }}>
              <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
              <LocationPicker position={coords} setPosition={setCoords} onAddressFound={handleAddressFound} />
            </MapContainer>
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px' }}>
            <div style={inputGroup}>
              <label style={labelStyle}>Calle detectada</label>
              <input style={inputStyle} value={direccion} readOnly placeholder="..." />
            </div>
            <div style={inputGroup}>
              <label style={labelStyle}>Ciudad</label>
              <input style={inputStyle} value={ciudad} readOnly placeholder="..." />
            </div>
          </div>

          <button type="submit" style={btnSubmitModal}>
            <MapPin size={18} /> Confirmar Ubicación
          </button>
        </form>
      </div>
    </div>
  );
};

// Estilos rápidos (podes usar los que ya tenías)
const modalOverlay = { position: 'fixed', top: 0, left: 0, width: '100%', height: '100%', background: 'rgba(15, 23, 42, 0.8)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 3000, backdropFilter: 'blur(8px)' };
const modalContent = { background: 'white', padding: '25px', borderRadius: '24px', width: '480px' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', marginBottom: '20px' };
const closeBtn = { background: '#f1f5f9', border: 'none', cursor: 'pointer', borderRadius: '8px' };
const inputGroup = { display: 'flex', flexDirection: 'column', gap: '5px' };
const labelStyle = { fontSize: '0.75rem', fontWeight: 'bold', color: '#475569' };
const inputStyle = { padding: '12px', borderRadius: '12px', border: '1px solid #e2e8f0', background: '#f8fafc' };
const mapContainerStyle = { height: '220px', borderRadius: '16px', overflow: 'hidden', border: '2px solid #f1f5f9' };
const btnSubmitModal = { padding: '16px', background: '#e67e22', color: 'white', border: 'none', borderRadius: '14px', fontWeight: 'bold', cursor: 'pointer', display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '10px' };

export default ModalNuevaSucursal;
